const items = $input.all();
const companies = [];
const seen = new Set();

for (const item of items) {
  let jobs = item.json;

  // RemoteOK returns an array; first element is often a legal notice object
  if (!Array.isArray(jobs)) {
    if (jobs.data && Array.isArray(jobs.data)) {
      jobs = jobs.data;
    } else {
      continue;
    }
  }

  for (const job of jobs) {
    // Skip non-job entries (e.g. the legal notice)
    if (!job.company && !job.company_name) continue;

    const companyName = job.company || job.company_name || 'Unknown';
    if (seen.has(companyName)) continue;
    seen.add(companyName);

    const website = job.company_url || job.url || 'Unknown';
    const tags = job.tags ? (Array.isArray(job.tags) ? job.tags.join(', ') : job.tags) : 'Unknown';
    const location = job.location || 'Remote';

    companies.push({
      json: {
        Company: companyName,
        Website: website,
        Careers_URL: job.url || 'Unknown',
        Country: 'Unknown',
        City: location,
        Sector: 'Technology',
        Subsector: 'Data / ML / Backend',
        Company_Stage: 'Unknown',
        Company_Scale: 'Unknown',
        Employer_Category: 'Remote Board',
        Remote: 'Yes',
        Visa_Sponsorship: 'Unknown',
        EOR: 'Unknown',
        Hiring_Geography: 'Global',
        Target_Roles: 'Data Engineer, ML Engineer, Backend Engineer',
        Tech_Stack: tags,
        Region_Eligibility: 'Unknown',
        Portfolio_Theme_Match: 'Unknown',
        Language_Requirement: 'English',
        Hiring_Confidence: 'High',
        Reason_Match: 'Actively hiring remote data/ML/Python roles on RemoteOK',
        Source: 'RemoteOK API',
        Cold_Outreach_Candidate: 'Yes',
        Visa_Sponsor_Register: 'Unknown'
      }
    });
  }
}

if (companies.length === 0) {
  return [{ json: { message: 'No companies found in RemoteOK response' } }];
}

return companies;
